mapper.select:
SELECT o.*, u.real_name, m.account_no AS member_account_no, (SELECT COUNT(*) FROM sales_detail WHERE order_id = o.order_id) AS detail_count FROM sales_order o LEFT JOIN sys_user u ON o.user_id = u.user_id LEFT JOIN member m ON o.member_id = m.member_id
AND o.order_no LIKE CONCAT('%', #{keyword}, '%')
ORDER BY o.create_time DESC LIMIT #{offset}, #{limit}
